			Depth: 0,
			From:  labels.ParseLabelArray("a", "c", "b"),
			To:    labels.ParseLabelArray("d", "e", "f"),
			DPorts: []*models.Port{
				{
					Name:     "HTTP",
					Port:     80,
					Protocol: "TCP",
				},
				{
					Name:     "HTTPs",
					Port:     442,
					Protocol: "TCP",
				},
			},
			rulesSelect: false,
		},
		"From: [unspec:a, unspec:b, unspec:c] => To: [unspec:d, unspec:e, unspec:f] Ports: [80/TCP, 442/TCP]": {
			Trace: 1,
			Depth: 0,
			From:  labels.ParseLabelArray("a", "c", "b"),
			To:    labels.ParseLabelArray("d", "e", "f"),
			DPorts: []*models.Port{
				{
					Port:     80,
					Protocol: "TCP",
				},
				{
					Port:     442,
					Protocol: "TCP",
				},
