	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	logger.SetOutput(&buf)

	ctx := context.Background()
	testResult := map[string]string{"status": "evaluated"}

	selectorCache := NewSelectorCache(identity.IdentityMap{})
	logger.LogEvaluation(ctx, "test-policy-key", selectorCache, testResult)

	// Verify JSON output was written
	output := buf.String()
	require.Greater(t, len(output), 0)

	// Parse and verify the JSON structure
	var data map[string]interface{}
	err := json.Unmarshal([]byte(output), &data)
	require.NoError(t, err)
	require.Equal(t, "test-policy-key", data[logfields.PolicyKey])
	require.True(t, data["selector_cache_set"].(bool))
}

func TestPolicyAuditLogger_SetOutput(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)

	// Initially no output
	var buf1 bytes.Buffer
	logger.SetOutput(&buf1)
	logger.LogDecision(identity.NumericIdentity(200), "policy1", "ALLOW", "reason1")

	// Verify output was written
	require.Greater(t, buf1.Len(), 0)

	// Set new output
	var buf2 bytes.Buffer
	logger.SetOutput(&buf2)
	logger.LogDecision(identity.NumericIdentity(201), "policy2", "DENY", "reason2")

	// First buffer should not receive new data (or it remains unchanged after setup)
	buf1Len := buf1.Len()

	// Second buffer should have new data
	require.Greater(t, buf2.Len(), 0)

	// Verify second buffer has the new entry
	var data map[string]interface{}
	err := json.Unmarshal([]byte(buf2.String()), &data)
	require.NoError(t, err)
	require.Equal(t, "policy2", data["policy"])
}

func TestPolicyAuditLogger_ConcurrentLogging(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	logger.SetOutput(&buf)

	// Log from multiple goroutines concurrently
	done := make(chan bool, 3)

	go func() {
		for i := 0; i < 10; i++ {
			logger.LogDecision(identity.NumericIdentity(i), "policy-a", "ALLOW", "concurrent test")
		}
		done <- true
	}()

	go func() {
		for i := 10; i < 20; i++ {
			logger.LogDecision(identity.NumericIdentity(i), "policy-b", "DENY", "concurrent test")
		}
		done <- true
	}()

	go func() {
		for i := 0; i < 5; i++ {
			logger.SetLogLevel(logrus.DebugLevel)
			logger.SetLogLevel(logrus.InfoLevel)
		}
		done <- true
	}()

	// Wait for all goroutines to complete
	for i := 0; i < 3; i++ {
		<-done
	}

	// Verify output contains entries
	output := buf.String()
	require.Greater(t, len(output), 0)

	// Count number of JSON entries
	lines := bytes.Split(bytes.TrimSpace(buf.Bytes()), []byte("\n"))
	require.Equal(t, 20, len(lines))
}

func TestPolicyAuditLogger_LogLevel_Filtering(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.ErrorLevel)

	// These should be logged based on the level
	logger.LogDecision(identity.NumericIdentity(300), "policy", "ALLOW", "error level test")

	// Change level and test again
	logger.SetLogLevel(logrus.DebugLevel)
	logger.LogDecision(identity.NumericIdentity(301), "policy", "DENY", "debug level test")

	// Should not panic or cause errors
}

func TestPolicyAuditLogger_JSON_MarshalError_Handling(t *testing.T) {
	// Create a mock writer that fails
	failingWriter := &failingWriterMock{shouldFail: true}
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	logger.SetOutput(failingWriter)

	// This should not panic even if the write fails
	logger.LogDecision(identity.NumericIdentity(400), "policy", "ALLOW", "failing write test")
}

// failingWriterMock is a mock io.Writer that can be configured to fail
type failingWriterMock struct {
	shouldFail bool
}

func (f *failingWriterMock) Write(p []byte) (n int, err error) {
	if f.shouldFail {
		return 0, bytes.ErrTooLarge
	}
	return len(p), nil
}

