package policy

import (
	"context"
	"encoding/json"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-audit")

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex
	level  logrus.Level
	output io.Writer
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified log level.
func NewPolicyAuditLogger(level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		level:  level,
		output: nil,
	}
}

// SetOutput sets a custom output writer for the audit logger.
// If output is nil, logs will be written to the default logger only.
func (pal *PolicyAuditLogger) SetOutput(w io.Writer) {
	pal.Lock()
	defer pal.Unlock()
	pal.output = w
}

// LogDecision logs a policy decision verdict for an identity with a reason.
func (pal *PolicyAuditLogger) LogDecision(id identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.Lock()
	defer pal.Unlock()

	fields := logrus.Fields{
		logfields.Identity: id,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	}

	scopedLog := log.WithFields(fields)

	// Log based on the configured level
	switch pal.level {
	case logrus.DebugLevel:
		scopedLog.Debug("Policy decision")
	case logrus.InfoLevel:
		scopedLog.Info("Policy decision")
	case logrus.WarnLevel:
		scopedLog.Warn("Policy decision")
	case logrus.ErrorLevel:
		scopedLog.Error("Policy decision")
	default:
		scopedLog.Info("Policy decision")
	}

	// Write JSON-structured audit log to custom output if configured
	if pal.output != nil {
		pal.writeJSONAuditLog(map[string]interface{}{
			logfields.Identity: id,
			"policy":           policy,
			"verdict":          verdict,
			"reason":           reason,
		})
	}
}

// LogEvaluation logs the result of a policy evaluation for a given policy key.
// It evaluates the result against the selector cache to provide detailed audit information.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.Lock()
	defer pal.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
		"evaluation_result": result,
	}

	if selectorCache != nil {
		fields["selector_cache_exists"] = true
	}

	scopedLog := log.WithFields(fields)

	// Log based on the configured level
	switch pal.level {
	case logrus.DebugLevel:
		scopedLog.Debug("Policy evaluation")
	case logrus.InfoLevel:
		scopedLog.Info("Policy evaluation")
	case logrus.WarnLevel:
		scopedLog.Warn("Policy evaluation")
	case logrus.ErrorLevel:
		scopedLog.Error("Policy evaluation")
	default:
		scopedLog.Info("Policy evaluation")
	}

	// Write JSON-structured audit log to custom output if configured
	if pal.output != nil {
		auditData := map[string]interface{}{
			logfields.PolicyKey:  policyKey,
			"evaluation_result":  result,
			"selector_cache_set": selectorCache != nil,
		}
		pal.writeJSONAuditLog(auditData)
	}
}

// writeJSONAuditLog writes structured audit log data as JSON to the configured output.
func (pal *PolicyAuditLogger) writeJSONAuditLog(data map[string]interface{}) {
	if pal.output == nil {
		return
	}

	jsonData, err := json.Marshal(data)
	if err != nil {
		log.WithError(err).Warn("Failed to marshal audit log data to JSON")
		return
	}

	_, err = pal.output.Write(append(jsonData, '\n'))
	if err != nil {
		log.WithError(err).Warn("Failed to write audit log data")
	}
}

// SetLogLevel updates the configured log level for this audit logger.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.level = level
}

// GetLogLevel returns the current log level of this audit logger.
func (pal *PolicyAuditLogger) GetLogLevel() logrus.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.level
}

